impl Solution { pub fn valid_square(p1: Vec<i32>, p2: Vec<i32>, p3: Vec<i32>, p4: Vec<i32>) -> bool { let mut black_d = vec![]; let black_p = vec![p1, p2, p3, p4]; for i in 0..4 { for j in i + 1..4 { black_d.push((black_p[i][0] - black_p[j][0]).pow(2) + (black_p[i][1] - black_p[j][1]).pow(2)); } } black_d.sort(); black_d[0] > 0 && black_d[0] == black_d[3] && black_d[4] == black_d[5] && black_d[0] * 2 == black_d[4] } }